import{_ as e,o as a,c as d,a2 as r}from"./chunks/framework.Cr-Z7ngm.js";const _=JSON.parse('{"title":"Wise国际汇款","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"deposit/wise.md","filePath":"zh-CN/deposit/wise.md"}'),i={name:"deposit/wise.md"};function s(o,t,l,n,h,p){return a(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="wise国际汇款" tabindex="-1">Wise国际汇款 <a class="header-anchor" href="#wise国际汇款" aria-label="Permalink to &quot;Wise国际汇款&quot;">​</a></h1><p>Wise（原名 TransferWise）是国际汇款和货币转换服务平台，可以较低费用完成国际转账，将资金转入长桥新加坡账户。</p><table tabindex="0"><thead><tr><th>项目</th><th>说明</th></tr></thead><tbody><tr><td>支持币种</td><td>美元（USD）、新加坡元（SGD）</td></tr><tr><td>到账时间</td><td>约 5 分钟至 3 个工作日，取决于入金币种</td></tr><tr><td>手续费</td><td>长桥免费；Wise 平台可能收取汇款手续费，以 Wise 实际收取为准</td></tr></tbody></table><h2 id="收款账户信息" tabindex="-1">收款账户信息 <a class="header-anchor" href="#收款账户信息" aria-label="Permalink to &quot;收款账户信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>内容</th></tr></thead><tbody><tr><td>账户持有人</td><td>LONG BRIDGE SEC</td></tr><tr><td>银行账号</td><td>0725885663</td></tr><tr><td>银行名称</td><td>DBS BANK LTD</td></tr><tr><td>SWIFT/BIC</td><td>DBSSSGSGXXX</td></tr><tr><td>汇款备注</td><td>填写证券账户号（如 SG10039100），<strong>必填</strong></td></tr></tbody></table><h2 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h2><ol><li>打开长桥 App，进入<strong>资产 → 全部功能 → 存入资金 → 选择币种（USD 或 SGD）→ Wise</strong>，查看并复制收款账户信息</li><li>在 Wise App 或网页端填入收款账户信息，汇款备注填写你的证券账户号（必填）</li><li>完成汇款后，在 Wise App 截图（需包含 Wise 账号及汇款至 Long Bridge 的交易记录页面）</li><li>返回长桥 App，上传汇款凭证截图</li></ol><h2 id="单向限制与同名账户要求" tabindex="-1">单向限制与同名账户要求 <a class="header-anchor" href="#单向限制与同名账户要求" aria-label="Permalink to &quot;单向限制与同名账户要求&quot;">​</a></h2><ul><li>首次通过 Wise 入金后，可以入金但不能通过 Wise 出金</li><li>不接受第三方汇款（非本人账户），退回资金产生的手续费由客户自行承担</li><li>转账账户名必须与长桥证券账户名同名</li></ul>',9)])])}const b=e(i,[["render",s]]);export{_ as __pageData,b as default};
